mapper.select:
SELECT 
    /* 1. 제목 및 데이터 기준 ID 설정 */


            '전 노선 운영현황' AS linetitle,
            NULL AS station_id


            (SELECT line_name || ' | ' || station_name || ' 운영현황' 
             FROM storage.local_amenities 
             WHERE station_id = #{station_id} 
             LIMIT 1) AS linetitle,
            #{station_id} AS station_id

    ,

    /* 2. 전체 노선 수 및 역 수 (전체 현황용) */
    (SELECT COUNT(DISTINCT line_name) FROM storage.local_amenities) AS linetotal,
    (SELECT COUNT(*) FROM storage.local_amenities) AS stationtotal,

    /* 3. 장애 / 이슈 건수 필터링 */
    (SELECT COUNT(*) FROM storage.incident 
     WHERE incident_status IN ('1', '2')

         AND incident_station_id = #{station_id}

    ) AS incident_count,

    /* 4. 총 물품보관함 개수 필터링 */
    COALESCE((
        SELECT SUM(li.local_small + li.local_middle + li.local_large)
        FROM storage.locker_inventory li

            JOIN storage.local l ON li.local_id = l.local_id
            WHERE l.station_id = #{station_id}

    ), 0) AS total_lockers,

    /* 5. 사용 중인 물품보관함 개수 필터링 */
    COALESCE((
        SELECT SUM((li.local_small + li.local_middle + li.local_large) - 
                   (lu.able_small + lu.able_middle + lu.able_large))
        FROM storage.locker_inventory li
        LEFT JOIN (
            SELECT DISTINCT ON (local_id) * FROM storage.locker_usage 
            ORDER BY local_id, observed_at DESC
        ) lu ON li.local_id = lu.local_id

            JOIN storage.local l ON li.local_id = l.local_id
            WHERE l.station_id = #{station_id}

    ), 0) AS used_lockers,

    /* 6. 시간대별 사용률(평균) 필터링 */
    COALESCE((
        SELECT ROUND(AVG(((li.local_small + li.local_middle + li.local_large) - 
                          (lu.able_small + lu.able_middle + lu.able_large))::numeric / 
                         NULLIF((li.local_small + li.local_middle + li.local_large), 0) * 100), 1)
        FROM storage.locker_inventory li
        JOIN (
            SELECT DISTINCT ON (local_id) * FROM storage.locker_usage 
            ORDER BY local_id, observed_at DESC
        ) lu ON li.local_id = lu.local_id

            JOIN storage.local l ON li.local_id = l.local_id
            WHERE l.station_id = #{station_id}

    ), 0) AS hour_usedlocker,

    /* 7. 최근 7일 장애 발생 현황 필터링 */
    (SELECT COUNT(*) FROM storage.incident 
     WHERE create_at >= CURRENT_DATE - INTERVAL '7 days'

         AND incident_station_id = #{station_id}

    ) AS weekly_issue
